UPDATE

MST.TB_IPMS_SVC_MST A
SET
	A.DMODIFY_DT = current_timestamp

		, A.SIPMS_SVC_NM = #{sipmsSvcNm, jdbcType=VARCHAR}


		, A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=VARCHAR}


		, A.SSVC_HGROUP_CD = #{ssvcHgroupCd, jdbcType=CHAR}


		, A.SSVC_MGROUP_CD = #{ssvcMgroupCd, jdbcType=CHAR}


		, A.SSVC_LGROUP_CD = #{ssvcLgroupCd, jdbcType=CHAR}


		, A.SEX_SVC_CD = #{sexSvcCd, jdbcType=CHAR}


		, A.SSVC_USE_TYPE_CD = #{ssvcUseTypeCd, jdbcType=CHAR}


		, A.SUSE_TYPE_CD = #{suseTypeCd, jdbcType=CHAR}


		, A.SCOMMENT = #{scomment, jdbcType=VARCHAR}


		, A.DCREATE_DT = #{dcreateDt, jdbcType=TIMESTAMP}


		, A.SCREATE_ID = #{screateId, jdbcType=VARCHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

