SELECT 
	   , A.RNUM FROM (
	SELECT  
	   , ROWNUM RNUM FROM (
		SELECT



		FROM MST.TB_IPMS_SVC_MST A



		ORDER BY A.SSVC_HGROUP_CD ASC, C.SEX_LINK_USE_TYPE_CD DESC, C.SSVC_MGROUP_NM ASC, C.SSVC_MGROUP_NM1 ASC, A.SIPMS_SVC_NM ASC, A.SASSIGN_TYPE_CD ASC
	) A WHERE ROWNUM <= #{lastIndex}
)A WHERE RNUM >= #{firstIndex}

SELECT SSVC_MGROUP_CD , SSVC_MGROUP_NM FROM ( SELECT '' AS SSVC_MGROUP_CD , '전체' AS SSVC_MGROUP_NM, '0' AS ORD_SEQ UNION ALL SELECT DISTINCT SUBSTR(SSVC_MGROUP_CD ,0,4) , SSVC_MGROUP_NM, '1' AS ORD_SEQ FROM MST.TB_SVC_MGROUP_CD
WHERE SSVC_HGROUP_CD = #{ssvcHgroupCd, jdbcType=CHAR}
) ORDER BY ORD_SEQ, SSVC_MGROUP_NM

SELECT SSVC_MGROUP_CD, SSVC_MGROUP_NM1 FROM ( SELECT '' AS SSVC_MGROUP_CD , '전체' AS SSVC_MGROUP_NM1, '0' as ORD_SEQ UNION ALL SELECT DISTINCT SUBSTR(SSVC_MGROUP_CD ,5,2) , SSVC_MGROUP_NM1 , '1' as ORD_SEQ FROM MST.TB_SVC_MGROUP_CD
WHERE SSVC_MGROUP_CD ILIKE #{ssvcMainClsCode, jdbcType=CHAR} || '%'
) ORDER BY ORD_SEQ, SSVC_MGROUP_NM1

SELECT SSVC_MGROUP_CD, SSVC_MGROUP_NM, SSVC_MGROUP_NM1, SEX_LINK_USE_TYPE_CD
FROM MST.TB_SVC_MGROUP_CD

	WHERE  SSVC_HGROUP_CD = #{ssvcHgroupCd, jdbcType=CHAR}

SELECT SSVC_LGROUP_CD, SSVC_LGROUP_NM 
FROM MST.TB_SVC_LGROUP_CD

	WHERE SSVC_HGROUP_CD = #{ssvcHgroupCd, jdbcType=CHAR} AND SSVC_MGROUP_CD = #{ssvcMgroupCd, jdbcType=CHAR}

SELECT SEX_LINK_USE_TYPE_CD 
FROM MST.TB_SVC_MGROUP_CD
WHERE SSVC_HGROUP_CD = #{ssvcHgroupCd, jdbcType=CHAR} AND SSVC_MGROUP_CD = #{ssvcMgroupCd, jdbcType=CHAR}
